import type { CareerQuestion } from "./rrt-questions";

export const addictionsCounsellorQuestionsBatch2: CareerQuestion[] = [
  { id: "cac-501", stem: "A client in early recovery reports intense cravings triggered by driving past their old dealer's neighborhood. Which technique is MOST appropriate to teach first?", options: ["Urge surfing and mindfulness-based coping","Aversion therapy conditioning","Confrontational intervention","Psychodynamic exploration of childhood trauma"], correctIndex: 0, rationale: "Urge surfing teaches clients to observe cravings without acting on them, recognizing that cravings are time-limited and will pass. This is a practical, evidence-based coping skill for trigger management.", difficulty: 2, category: "Relapse Prevention", topic: "Coping Skills" },
  { id: "cac-502", stem: "During a motivational interviewing session, a client says, 'I know drinking is hurting my family, but I don't think I can stop.' The counselor should:", options: ["Reflect the ambivalence by saying, 'You see the harm alcohol causes and you're uncertain about your ability to change'","Tell the client they must stop immediately for their family's sake","Point out the client is in denial","Recommend inpatient treatment right away"], correctIndex: 0, rationale: "Reflecting ambivalence is a core MI technique that validates both sides of the client's conflict without judgment, fostering exploration of their own motivation for change.", difficulty: 2, category: "Motivational Interviewing", topic: "Core Techniques" },
  { id: "cac-503", stem: "Naltrexone works by which mechanism to treat alcohol use disorder?", options: ["Blocking opioid receptors to reduce the rewarding effects of alcohol","Inhibiting aldehyde dehydrogenase to cause adverse reactions","Enhancing GABA transmission to reduce withdrawal symptoms","Blocking dopamine reuptake in the nucleus accumbens"], correctIndex: 0, rationale: "Naltrexone is an opioid antagonist that blocks mu-opioid receptors, reducing the pleasurable and reinforcing effects of alcohol, thereby decreasing cravings and heavy drinking days.", difficulty: 3, category: "Pharmacology", topic: "Medication-Assisted Treatment" },
  { id: "cac-504", stem: "A client with opioid use disorder is being maintained on methadone. Which statement about methadone is accurate?", options: ["It is a full mu-opioid agonist with a long half-life that reduces withdrawal and cravings","It is a partial agonist that has a ceiling effect for respiratory depression","It can be prescribed by any physician in an office-based setting","It is only effective for short-term detoxification, not maintenance"], correctIndex: 0, rationale: "Methadone is a full mu-opioid agonist with a long half-life (24-36 hours), allowing once-daily dosing. It must be dispensed through federally regulated opioid treatment programs.", difficulty: 3, category: "Pharmacology", topic: "Medication-Assisted Treatment" },
  { id: "cac-505", stem: "According to the Stages of Change model, a client who has been sober for 8 months and is actively working their recovery program is in which stage?", options: ["Maintenance","Action","Preparation","Contemplation"], correctIndex: 0, rationale: "The Maintenance stage begins after 6 months of sustained change. The client is actively working to prevent relapse and consolidate gains made during the Action stage.", difficulty: 1, category: "Theories of Addiction", topic: "Stages of Change" },
  { id: "cac-506", stem: "A counselor notices a colleague appears intoxicated at work and smells of alcohol. The counselor's FIRST ethical obligation is to:", options: ["Report the concern to a supervisor immediately to protect client welfare","Confront the colleague and insist they go to treatment","Ignore it to maintain collegial relationships","Document it but take no immediate action"], correctIndex: 0, rationale: "Protecting client welfare is the primary ethical obligation. Reporting to a supervisor ensures clients are not harmed and that the colleague can receive appropriate assistance.", difficulty: 2, category: "Ethics", topic: "Professional Responsibility" },
  { id: "cac-507", stem: "A client presenting with pinpoint pupils, respiratory depression, and decreased level of consciousness is MOST likely experiencing:", options: ["Opioid overdose","Alcohol withdrawal","Stimulant intoxication","Benzodiazepine withdrawal"], correctIndex: 0, rationale: "The classic triad of opioid overdose includes miosis (pinpoint pupils), respiratory depression, and decreased consciousness. This requires immediate administration of naloxone.", difficulty: 1, category: "Substance Use Disorders", topic: "Intoxication and Withdrawal" },
  { id: "cac-508", stem: "Which withdrawal syndrome can be life-threatening and requires medical supervision?", options: ["Alcohol withdrawal with risk of delirium tremens","Cannabis withdrawal","Opioid withdrawal","Stimulant withdrawal"], correctIndex: 0, rationale: "Alcohol withdrawal can progress to delirium tremens (DTs), involving seizures, severe autonomic instability, and hallucinations, with mortality rates of 5-15% without treatment. Medical detox is essential.", difficulty: 2, category: "Substance Use Disorders", topic: "Intoxication and Withdrawal" },
  { id: "cac-509", stem: "In group therapy for substance use disorders, a member becomes verbally aggressive toward another member. The counselor should FIRST:", options: ["Calmly intervene to ensure safety and redirect the interaction using group norms","Allow the group to handle it without intervention","Ask the aggressive member to leave immediately","Ignore the behavior to avoid reinforcing it"], correctIndex: 0, rationale: "The counselor's primary responsibility is ensuring physical and emotional safety of all group members. Calmly intervening and referencing established group norms models appropriate conflict resolution.", difficulty: 2, category: "Group Therapy", topic: "Group Management" },
  { id: "cac-510", stem: "The CAGE questionnaire assesses for:", options: ["Potential alcohol use problems using four screening questions","Cannabis use severity","Cocaine addiction risk","Gambling disorder symptoms"], correctIndex: 0, rationale: "CAGE (Cut down, Annoyed, Guilty, Eye-opener) is a brief 4-question screening tool for alcohol problems. Two or more positive answers suggest problematic alcohol use requiring further assessment.", difficulty: 1, category: "Clinical Assessment", topic: "Screening Tools" },
  { id: "cac-511", stem: "Buprenorphine differs from methadone primarily because it:", options: ["Is a partial opioid agonist with a ceiling effect for respiratory depression","Is a full opioid antagonist that blocks all opioid effects","Can only be administered intravenously","Has no abuse potential whatsoever"], correctIndex: 0, rationale: "Buprenorphine is a partial mu-opioid agonist with a ceiling effect, meaning respiratory depression plateaus at higher doses, making it safer than full agonists like methadone.", difficulty: 3, category: "Pharmacology", topic: "Medication-Assisted Treatment" },
  { id: "cac-512", stem: "A Native American client seeking addiction treatment requests involvement of a traditional healer. The counselor should:", options: ["Support integration of traditional healing practices alongside evidence-based treatment","Explain that only evidence-based approaches are used in the program","Refer the client to a culturally specific program instead","Discourage the request as it may interfere with treatment"], correctIndex: 0, rationale: "Culturally competent care respects and integrates traditional healing practices. Research supports that incorporating cultural identity and traditional practices improves treatment outcomes for Indigenous populations.", difficulty: 2, category: "Cultural Competence", topic: "Diverse Populations" },
  { id: "cac-513", stem: "During crisis intervention with a suicidal client who has been using methamphetamine, the counselor's IMMEDIATE priority is:", options: ["Assess lethality by determining if the client has a specific plan, means, and intent","Begin motivational interviewing about drug use","Schedule a follow-up appointment for next week","Contact the client's family for collateral information"], correctIndex: 0, rationale: "Immediate lethality assessment (plan, means, intent, timeline) is the priority in crisis intervention. Stimulant intoxication/withdrawal increases suicide risk, making rapid assessment critical.", difficulty: 2, category: "Crisis Intervention", topic: "Suicide Assessment" },
  { id: "cac-514", stem: "The concept of 'cross-tolerance' means:", options: ["Tolerance to one substance extends to other pharmacologically similar substances","A person can use multiple substances without any effects","Withdrawal from one substance prevents withdrawal from another","Treatment for one addiction automatically treats all addictions"], correctIndex: 0, rationale: "Cross-tolerance occurs when tolerance to one substance confers tolerance to pharmacologically similar substances (e.g., alcohol and benzodiazepines both affect GABA receptors).", difficulty: 3, category: "Substance Use Disorders", topic: "Pharmacological Concepts" },
  { id: "cac-515", stem: "Marlatt and Gordon's relapse prevention model identifies which as a primary determinant of relapse?", options: ["High-risk situations combined with inadequate coping responses","Genetic predisposition alone","Lack of willpower","Insufficient medication dosage"], correctIndex: 0, rationale: "Marlatt's model emphasizes that relapse occurs when individuals encounter high-risk situations without adequate coping skills, leading to decreased self-efficacy and positive outcome expectancies for substance use.", difficulty: 3, category: "Relapse Prevention", topic: "Theoretical Models" },
  { id: "cac-516", stem: "A counselor working with a client who has co-occurring bipolar disorder and alcohol use disorder should:", options: ["Coordinate with a psychiatrist for integrated treatment of both conditions simultaneously","Treat the addiction first and then address the mental health disorder","Refer the client to a psychiatrist and discontinue addiction counseling","Focus only on the mental health disorder since it likely caused the addiction"], correctIndex: 0, rationale: "Integrated treatment addressing both disorders simultaneously is the evidence-based best practice for co-occurring disorders. Sequential treatment leads to poorer outcomes.", difficulty: 2, category: "Co-Occurring Disorders", topic: "Integrated Treatment" },
  { id: "cac-517", stem: "Which neurotransmitter system is MOST directly involved in the rewarding effects of substances of abuse?", options: ["Mesolimbic dopamine pathway","Serotonin system exclusively","Acetylcholine system","Histamine pathway"], correctIndex: 0, rationale: "The mesolimbic dopamine pathway (ventral tegmental area to nucleus accumbens) is the primary reward circuit. Most substances of abuse increase dopamine transmission in this pathway.", difficulty: 3, category: "Theories of Addiction", topic: "Neurobiology" },
  { id: "cac-518", stem: "A counselor discovers that a client's 12-year-old child is being left home alone while the client uses substances. The counselor is legally required to:", options: ["Report suspected child neglect to child protective services","Maintain confidentiality as 42 CFR Part 2 protects all information","Discuss the situation only with the client","Wait to see if the situation improves"], correctIndex: 0, rationale: "Mandated reporting of child abuse/neglect supersedes federal confidentiality regulations (42 CFR Part 2). Child safety takes priority over substance use treatment confidentiality.", difficulty: 2, category: "Ethics", topic: "Mandated Reporting" },
  { id: "cac-519", stem: "In motivational interviewing, OARS stands for:", options: ["Open questions, Affirmations, Reflections, Summaries","Observation, Assessment, Recommendation, Support","Outcomes, Actions, Results, Solutions","Open dialogue, Active listening, Reframing, Skill-building"], correctIndex: 0, rationale: "OARS represents the four core communication skills in MI: Open questions encourage exploration, Affirmations build confidence, Reflections demonstrate understanding, and Summaries link and transition.", difficulty: 1, category: "Motivational Interviewing", topic: "Core Techniques" },
  { id: "cac-520", stem: "Disulfiram (Antabuse) works by:", options: ["Inhibiting aldehyde dehydrogenase, causing unpleasant reactions when alcohol is consumed","Blocking opioid receptors to reduce alcohol cravings","Replacing alcohol's effect on GABA receptors","Increasing serotonin levels to reduce the desire to drink"], correctIndex: 0, rationale: "Disulfiram inhibits aldehyde dehydrogenase, causing accumulation of acetaldehyde when alcohol is consumed. This produces flushing, nausea, vomiting, and tachycardia, creating an aversive response.", difficulty: 2, category: "Pharmacology", topic: "Medication-Assisted Treatment" },
  { id: "cac-521", stem: "A client in a therapeutic community (TC) program refuses to participate in morning meeting. The BEST response is:", options: ["Explore the reason for refusal while explaining community expectations and natural consequences","Force the client to attend by threatening discharge","Allow the client to skip without discussion","Have peers confront the client aggressively"], correctIndex: 0, rationale: "In a TC model, participation is expected but should be explored therapeutically. Understanding resistance while clearly communicating expectations maintains the therapeutic relationship and community structure.", difficulty: 2, category: "Treatment Modalities", topic: "Therapeutic Communities" },
  { id: "cac-522", stem: "The ASI (Addiction Severity Index) assesses functioning in how many life domains?", options: ["Seven","Three","Five","Ten"], correctIndex: 0, rationale: "The ASI evaluates seven domains: medical, employment/support, drug use, alcohol use, legal, family/social, and psychiatric. It provides a comprehensive biopsychosocial assessment.", difficulty: 2, category: "Clinical Assessment", topic: "Assessment Tools" },
  { id: "cac-523", stem: "A client with alcohol use disorder reports drinking a fifth of vodka daily for the past 5 years and their last drink was 6 hours ago. The counselor should be MOST concerned about:", options: ["Onset of alcohol withdrawal syndrome including potential seizures","The client's nutritional status","Whether the client has tried to quit before","The client's legal history related to drinking"], correctIndex: 0, rationale: "With heavy, prolonged alcohol use and recent cessation, alcohol withdrawal can begin 6-24 hours after the last drink. Seizures can occur within 12-48 hours, requiring immediate medical assessment.", difficulty: 2, category: "Substance Use Disorders", topic: "Intoxication and Withdrawal" },
  { id: "cac-524", stem: "Contingency management in addiction treatment involves:", options: ["Providing tangible reinforcement for verifiable target behaviors such as negative drug screens","Punishing substance use through increased supervision","Removing all privileges until sobriety is achieved","Using confrontational techniques to address denial"], correctIndex: 0, rationale: "Contingency management is an evidence-based approach using positive reinforcement (vouchers, prizes, privileges) for verified prosocial behaviors like negative urine screens or treatment attendance.", difficulty: 2, category: "Treatment Modalities", topic: "Behavioral Interventions" },
  { id: "cac-525", stem: "42 CFR Part 2 specifically protects:", options: ["Substance use disorder treatment records from disclosure without patient consent","All medical records equally","Only records of illicit drug use","Mental health records exclusively"], correctIndex: 0, rationale: "42 CFR Part 2 provides enhanced federal confidentiality protections specifically for substance use disorder treatment records to reduce stigma and encourage treatment-seeking.", difficulty: 2, category: "Ethics", topic: "Confidentiality" },
  { id: "cac-526", stem: "A client who has been abstinent from cocaine for 3 months suddenly relapses after receiving a large bonus at work. This is BEST explained by:", options: ["Positive emotional states can be high-risk situations triggering substance use","The client was never truly motivated to stop using","Cocaine addiction cannot be treated without medication","The client needs a higher level of care"], correctIndex: 0, rationale: "Marlatt's relapse prevention model identifies positive emotional states (celebrations, windfalls) as high-risk situations. Clients often fail to recognize positive events as relapse triggers.", difficulty: 3, category: "Relapse Prevention", topic: "Risk Factors" },
  { id: "cac-527", stem: "The ASAM Criteria uses which dimensions to determine level of care placement?", options: ["Six dimensions including withdrawal potential, biomedical conditions, and readiness to change","Two dimensions: severity and duration","Four dimensions based on DSM-5 criteria","Eight dimensions based on the biopsychosocial model"], correctIndex: 0, rationale: "ASAM uses six dimensions: acute intoxication/withdrawal, biomedical conditions, emotional/behavioral conditions, readiness to change, relapse/continued use potential, and recovery environment.", difficulty: 3, category: "Clinical Assessment", topic: "Level of Care" },
  { id: "cac-528", stem: "When a client with fetal alcohol spectrum disorder (FASD) presents for treatment, the counselor should understand that:", options: ["Cognitive deficits may require simplified treatment materials and concrete language","FASD only affects individuals during childhood and resolves in adulthood","Standard treatment approaches work equally well for all clients","FASD is not relevant to addiction treatment planning"], correctIndex: 0, rationale: "FASD causes lifelong neurocognitive deficits including executive function impairment, requiring adapted treatment approaches with concrete language, visual aids, and simplified materials.", difficulty: 3, category: "Special Populations", topic: "Cognitive Impairment" },
  { id: "cac-529", stem: "In the contemplation stage of change, a client is MOST likely to:", options: ["Weigh the pros and cons of changing their substance use behavior","Actively participate in treatment and practice new skills","Have no awareness that their substance use is problematic","Be maintaining changes made over the past several months"], correctIndex: 0, rationale: "In Contemplation, clients are aware of the problem and consider change but are ambivalent. They weigh pros and cons but have not yet committed to action.", difficulty: 1, category: "Theories of Addiction", topic: "Stages of Change" },
  { id: "cac-530", stem: "A counselor suspects a client is experiencing serotonin syndrome. Which combination is MOST likely responsible?", options: ["An SSRI antidepressant combined with MDMA use","Alcohol combined with cannabis","Opioids combined with benzodiazepines","Nicotine combined with caffeine"], correctIndex: 0, rationale: "Serotonin syndrome occurs from excessive serotonergic activity. Combining SSRIs with MDMA (which releases serotonin) is a common cause, presenting with agitation, hyperthermia, clonus, and diaphoresis.", difficulty: 4, category: "Pharmacology", topic: "Drug Interactions" },
  { id: "cac-531", stem: "The 'abstinence violation effect' described by Marlatt refers to:", options: ["Cognitive and emotional response to a lapse that increases the probability of a full relapse","The physical withdrawal symptoms that occur when abstinence begins","Legal consequences of violating probation requirements","The body's physiological return to baseline after detoxification"], correctIndex: 0, rationale: "The abstinence violation effect involves self-blame and perceived loss of control after a lapse, leading to continued use. Reframing a lapse as a learning opportunity can prevent full relapse.", difficulty: 3, category: "Relapse Prevention", topic: "Theoretical Models" },
  { id: "cac-532", stem: "A pregnant client presents seeking treatment for opioid use disorder. The recommended pharmacological treatment is:", options: ["Methadone or buprenorphine maintenance throughout pregnancy","Immediate medically supervised withdrawal","Naltrexone injection","No medication, as all medications are contraindicated in pregnancy"], correctIndex: 0, rationale: "Opioid agonist therapy (methadone or buprenorphine) is recommended during pregnancy. Withdrawal is associated with fetal distress, miscarriage, and preterm labor. Naltrexone is not recommended.", difficulty: 3, category: "Pharmacology", topic: "Special Populations" },
  { id: "cac-533", stem: "Which of the following is a harm reduction strategy?", options: ["Needle exchange programs to reduce transmission of bloodborne infections","Requiring abstinence before providing any services","Refusing treatment until the client hits 'rock bottom'","Mandatory drug testing for employment as a condition of treatment"], correctIndex: 0, rationale: "Harm reduction aims to minimize negative consequences of substance use without requiring abstinence. Needle exchange programs reduce HIV/HCV transmission among people who inject drugs.", difficulty: 1, category: "Treatment Modalities", topic: "Harm Reduction" },
  { id: "cac-534", stem: "A counselor working with LGBTQ+ clients with substance use disorders should be aware that:", options: ["Minority stress, including discrimination and internalized stigma, contributes to higher rates of substance use","Sexual orientation is the primary cause of addiction","Standard treatment approaches require no modification","LGBTQ+ clients are less likely to develop substance use disorders"], correctIndex: 0, rationale: "Minority stress theory explains that experiences of discrimination, stigma, and identity concealment contribute to health disparities including higher rates of substance use in LGBTQ+ populations.", difficulty: 2, category: "Cultural Competence", topic: "LGBTQ+ Populations" },
  { id: "cac-535", stem: "The Clinical Institute Withdrawal Assessment for Alcohol (CIWA-Ar) measures:", options: ["Severity of alcohol withdrawal symptoms to guide pharmacological management","Readiness to change drinking behavior","Lifetime alcohol consumption patterns","Risk of developing alcohol use disorder"], correctIndex: 0, rationale: "CIWA-Ar is a validated 10-item tool that quantifies alcohol withdrawal severity (nausea, tremor, anxiety, agitation, etc.) to guide benzodiazepine dosing in medically managed withdrawal.", difficulty: 2, category: "Clinical Assessment", topic: "Screening Tools" },
  { id: "cac-536", stem: "In a group therapy session, a member shares that they used drugs over the weekend. Several group members respond with anger and judgment. The counselor should:", options: ["Acknowledge the group's feelings while redirecting toward supportive exploration of the lapse","Allow the confrontation to continue as a natural consequence","Remove the member who relapsed from the group","Ignore the reaction and move to the next topic"], correctIndex: 0, rationale: "The counselor should validate the group's emotional response while modeling a non-judgmental, therapeutic approach to relapse. This creates safety and transforms the event into a learning opportunity.", difficulty: 3, category: "Group Therapy", topic: "Group Dynamics" },
  { id: "cac-537", stem: "Wernicke-Korsakoff syndrome is caused by deficiency of:", options: ["Thiamine (vitamin B1) due to chronic alcohol use","Vitamin C due to poor nutrition","Iron due to gastrointestinal bleeding","Folate due to malabsorption"], correctIndex: 0, rationale: "Chronic alcohol use impairs thiamine absorption and utilization. Wernicke's encephalopathy (acute: confusion, ataxia, ophthalmoplegia) can progress to Korsakoff's syndrome (chronic: amnesia, confabulation).", difficulty: 2, category: "Substance Use Disorders", topic: "Medical Complications" },
  { id: "cac-538", stem: "Trauma-informed care in addiction treatment requires:", options: ["Recognizing the widespread impact of trauma and integrating knowledge into policies and practices","Requiring all clients to complete trauma-focused therapy before addiction treatment","Avoiding discussion of trauma to prevent re-traumatization","Screening for trauma only in female clients"], correctIndex: 0, rationale: "Trauma-informed care involves understanding, recognizing, and responding to trauma's effects across all aspects of service delivery, emphasizing safety, trustworthiness, and empowerment.", difficulty: 2, category: "Treatment Modalities", topic: "Trauma-Informed Care" },
  { id: "cac-539", stem: "A client reports using kratom to self-treat opioid withdrawal. The counselor should know that:", options: ["Kratom contains mitragynine which acts on opioid receptors and carries dependence risk","Kratom is FDA-approved for opioid withdrawal management","Kratom has no psychoactive properties","Kratom use never produces withdrawal symptoms"], correctIndex: 0, rationale: "Kratom contains alkaloids (mitragynine, 7-hydroxymitragynine) that act on mu-opioid receptors. It is not FDA-approved, carries dependence and withdrawal risk, and has inconsistent potency.", difficulty: 3, category: "Substance Use Disorders", topic: "Emerging Substances" },
  { id: "cac-540", stem: "The therapeutic alliance in addiction counseling is BEST described as:", options: ["A collaborative relationship characterized by agreement on goals, tasks, and an emotional bond","A power dynamic where the counselor directs all treatment decisions","A friendship between counselor and client","An adversarial relationship designed to break through denial"], correctIndex: 0, rationale: "Bordin's model defines the therapeutic alliance through three components: agreement on goals, agreement on tasks, and the quality of the emotional bond. It is the strongest predictor of treatment outcomes.", difficulty: 1, category: "Counseling Fundamentals", topic: "Therapeutic Relationship" },
  { id: "cac-541", stem: "Which assessment finding indicates the HIGHEST immediate risk for a client in alcohol withdrawal?", options: ["Grand mal seizure activity","Mild hand tremors","Slight anxiety and irritability","Mild nausea without vomiting"], correctIndex: 0, rationale: "Seizures represent a severe, potentially life-threatening complication of alcohol withdrawal, typically occurring 12-48 hours after last drink. Status epilepticus can be fatal without intervention.", difficulty: 1, category: "Crisis Intervention", topic: "Medical Emergencies" },
  { id: "cac-542", stem: "A counselor practicing from a cognitive-behavioral therapy perspective would MOST likely:", options: ["Help the client identify and challenge maladaptive thoughts that trigger substance use","Focus exclusively on unconscious conflicts from childhood","Use only experiential techniques without cognitive restructuring","Avoid discussing current thinking patterns"], correctIndex: 0, rationale: "CBT for addiction focuses on identifying cognitive distortions, automatic thoughts, and core beliefs that trigger substance use, then developing alternative thinking patterns and coping strategies.", difficulty: 2, category: "Treatment Modalities", topic: "CBT" },
  { id: "cac-543", stem: "Acamprosate (Campral) is used to treat alcohol use disorder by:", options: ["Modulating glutamate and GABA neurotransmission to reduce protracted withdrawal symptoms","Blocking opioid receptors to reduce cravings","Causing aversive reactions when alcohol is consumed","Replacing alcohol at GABA receptor sites"], correctIndex: 0, rationale: "Acamprosate restores the balance between excitatory (glutamate) and inhibitory (GABA) neurotransmission disrupted by chronic alcohol use, reducing protracted withdrawal symptoms like anxiety and insomnia.", difficulty: 4, category: "Pharmacology", topic: "Medication-Assisted Treatment" },
  { id: "cac-544", stem: "A counselor receives a court order requiring disclosure of a client's substance use treatment records. Under 42 CFR Part 2, the counselor should:", options: ["Comply only if the order meets the specific requirements of 42 CFR Part 2, including showing good cause","Immediately release all requested records","Refuse to release any records regardless of the court order","Release records but remove the client's name"], correctIndex: 0, rationale: "42 CFR Part 2 has stricter requirements than HIPAA for court orders. The order must meet specific criteria including a showing of good cause and limiting disclosure to essential information.", difficulty: 3, category: "Ethics", topic: "Confidentiality" },
  { id: "cac-545", stem: "A client with stimulant use disorder reports not sleeping for 4 days and is experiencing paranoid ideation. This presentation is MOST consistent with:", options: ["Stimulant-induced psychosis","Schizophrenia spectrum disorder","Generalized anxiety disorder","Major depressive episode"], correctIndex: 0, rationale: "Prolonged stimulant use with sleep deprivation commonly produces stimulant-induced psychosis with paranoid ideation, perceptual disturbances, and agitation. Symptoms typically resolve with abstinence and sleep.", difficulty: 2, category: "Substance Use Disorders", topic: "Intoxication Effects" },
  { id: "cac-546", stem: "The Twelve Steps were originally developed by:", options: ["Alcoholics Anonymous","The American Medical Association","The National Institute on Drug Abuse","The American Psychological Association"], correctIndex: 0, rationale: "The Twelve Steps were created by the co-founders of Alcoholics Anonymous (Bill Wilson and Dr. Bob Smith) in 1935 as a program of recovery from alcoholism.", difficulty: 1, category: "Treatment Modalities", topic: "Twelve-Step Programs" },
  { id: "cac-547", stem: "When conducting a biopsychosocial assessment, the 'social' domain includes:", options: ["Family relationships, social support, housing, employment, and legal issues","Only the client's psychiatric history","Blood pressure and heart rate","Neurological functioning and cognitive status"], correctIndex: 0, rationale: "The social domain encompasses environmental and interpersonal factors: family dynamics, social network, housing stability, employment, education, legal involvement, and community resources.", difficulty: 1, category: "Clinical Assessment", topic: "Biopsychosocial Assessment" },
  { id: "cac-548", stem: "A client on buprenorphine/naloxone (Suboxone) reports they attempted to inject the medication. The naloxone component:", options: ["Precipitates withdrawal when the combination is injected, deterring misuse","Enhances the euphoric effects of buprenorphine","Has no effect regardless of route of administration","Treats any concurrent pain the client may experience"], correctIndex: 0, rationale: "Naloxone is added to buprenorphine as an abuse deterrent. When taken sublingually as prescribed, naloxone has poor bioavailability. When injected, naloxone blocks opioid receptors and precipitates withdrawal.", difficulty: 3, category: "Pharmacology", topic: "Medication-Assisted Treatment" },
  { id: "cac-549", stem: "A counselor is working with a mandated client who states, 'I'm only here because my probation officer made me come.' Using MI, the counselor should:", options: ["Roll with resistance and explore what the client values, looking for any discrepancy between values and behavior","Confront the client about their need for treatment","Document non-compliance and report to probation","Explain that treatment won't work unless they want to be there"], correctIndex: 0, rationale: "Rolling with resistance is a core MI principle. Exploring values and developing discrepancy between current behavior and personal goals can build intrinsic motivation even in mandated clients.", difficulty: 2, category: "Motivational Interviewing", topic: "Resistance" },
  { id: "cac-550", stem: "Which of the following is an example of an evidence-based practice for treating substance use disorders?", options: ["Motivational Enhancement Therapy (MET)","Scared Straight programs","Boot camp interventions","Unstructured peer support without clinical oversight"], correctIndex: 0, rationale: "MET is an evidence-based brief intervention derived from motivational interviewing principles. Research consistently demonstrates its effectiveness in reducing substance use across multiple populations.", difficulty: 1, category: "Treatment Modalities", topic: "Evidence-Based Practices" },
  { id: "cac-551", stem: "A client with alcohol use disorder has a blood alcohol level of 0.35 g/dL and is conscious. This indicates:", options: ["Significant physiological tolerance to alcohol, as this level can be fatal in non-tolerant individuals","Normal social drinking","Mild intoxication only","The test result is likely erroneous"], correctIndex: 0, rationale: "A BAL of 0.35 g/dL is potentially lethal in non-tolerant individuals. Consciousness at this level indicates significant neuroadaptation and tolerance, consistent with severe alcohol use disorder.", difficulty: 3, category: "Substance Use Disorders", topic: "Tolerance" },
  { id: "cac-552", stem: "In family systems theory, 'enabling' refers to:", options: ["Behaviors by family members that inadvertently support and maintain the addicted person's substance use","Teaching the client new coping skills","Providing financial support for treatment costs","Setting appropriate boundaries with the addicted family member"], correctIndex: 0, rationale: "Enabling includes actions like covering for the person, providing money, minimizing consequences, and rescuing from problems. These behaviors, though well-intentioned, perpetuate the addiction cycle.", difficulty: 1, category: "Family Therapy", topic: "Family Dynamics" },
  { id: "cac-553", stem: "A counselor working with adolescents should be aware that the adolescent brain:", options: ["Has an underdeveloped prefrontal cortex, making teens more vulnerable to impulsive substance use decisions","Is fully developed by age 14 with mature decision-making capacity","Is less sensitive to the rewarding effects of substances than the adult brain","Is protected from the neurotoxic effects of alcohol"], correctIndex: 0, rationale: "The prefrontal cortex (responsible for judgment, impulse control, decision-making) continues developing until approximately age 25, making adolescents more vulnerable to substance use and its effects.", difficulty: 2, category: "Special Populations", topic: "Adolescents" },
  { id: "cac-554", stem: "The primary purpose of a toxicology screen in addiction treatment is to:", options: ["Provide objective data to inform clinical decision-making and treatment planning","Punish the client for using substances","Provide evidence for legal proceedings","Satisfy insurance company requirements"], correctIndex: 0, rationale: "Drug testing in treatment is a clinical tool that provides objective data on substance use patterns, informs level of care decisions, identifies undisclosed substance use, and monitors treatment progress.", difficulty: 1, category: "Clinical Assessment", topic: "Drug Testing" },
  { id: "cac-555", stem: "Dialectical behavior therapy (DBT) in addiction treatment emphasizes:", options: ["Balancing acceptance and change strategies while building distress tolerance and emotion regulation skills","Exclusively focusing on behavioral modification without addressing emotions","Avoiding discussion of emotional experiences","Using only cognitive techniques without mindfulness"], correctIndex: 0, rationale: "DBT combines acceptance-based strategies with change-oriented techniques. Core skill modules include mindfulness, distress tolerance, emotion regulation, and interpersonal effectiveness.", difficulty: 3, category: "Treatment Modalities", topic: "DBT" },
  { id: "cac-556", stem: "A client says, 'Everyone in my family drinks. It's just what we do.' This statement reflects:", options: ["Cultural and familial norms that normalize heavy drinking and may impede recognition of problematic use","A genetic test result confirming alcoholism","Active psychosis requiring immediate intervention","An example of therapeutic insight"], correctIndex: 0, rationale: "Family and cultural norms significantly influence substance use patterns and treatment engagement. Normalizing heavy drinking within a family system can create barriers to recognizing problematic use.", difficulty: 2, category: "Cultural Competence", topic: "Family Culture" },
  { id: "cac-557", stem: "Which statement about dual diagnosis/co-occurring disorders is accurate?", options: ["Substance use disorders and mental health disorders each influence the course and prognosis of the other","Mental health disorders always precede substance use disorders","Treating one disorder automatically resolves the other","Co-occurring disorders are rare in treatment settings"], correctIndex: 0, rationale: "Co-occurring disorders have a bidirectional relationship where each condition influences the onset, course, and treatment of the other. Prevalence in treatment settings ranges from 50-75%.", difficulty: 2, category: "Co-Occurring Disorders", topic: "General Concepts" },
  { id: "cac-558", stem: "The concept of 'people, places, and things' in recovery refers to:", options: ["Environmental triggers associated with past substance use that should be identified and managed","A treatment modality used exclusively in inpatient settings","Legal restrictions placed on individuals in recovery","A pharmacological approach to treating addiction"], correctIndex: 0, rationale: "Through classical conditioning, people, places, and things associated with past use become conditioned cues that trigger cravings. Identifying and managing these triggers is fundamental to relapse prevention.", difficulty: 1, category: "Relapse Prevention", topic: "Trigger Management" },
  { id: "cac-559", stem: "A counselor notices persistent pattern of arriving late, frequently canceling sessions, and avoiding discussion of substance use in a client who initially appeared motivated. This MOST likely represents:", options: ["Ambivalence about change, which is a normal part of the recovery process","Definitive evidence the client does not want to recover","A personality disorder diagnosis","Manipulation that requires confrontation"], correctIndex: 0, rationale: "Ambivalence is expected in the change process. These behaviors may indicate the client is revisiting contemplation stage. Exploring ambivalence non-judgmentally is more productive than labeling as resistance.", difficulty: 3, category: "Counseling Fundamentals", topic: "Process Issues" },
  { id: "cac-560", stem: "Which of the following substances produces physical dependence and a withdrawal syndrome that includes rebound anxiety, insomnia, and seizure risk?", options: ["Benzodiazepines","Cannabis","Psilocybin","LSD"], correctIndex: 0, rationale: "Benzodiazepines produce physical dependence with a potentially dangerous withdrawal syndrome including anxiety, insomnia, tremor, and seizures. Like alcohol withdrawal, it can be life-threatening.", difficulty: 2, category: "Substance Use Disorders", topic: "Withdrawal Syndromes" },
  { id: "cac-561", stem: "In the context of addiction, 'tolerance' is BEST defined as:", options: ["The need for increasing amounts of a substance to achieve the same effect, or diminished effect with continued use of the same amount","The ability to function normally while under the influence","A decision to accept substance use as part of one's lifestyle","The body's immediate reaction to a new substance"], correctIndex: 0, rationale: "Tolerance involves neuroadaptation where the body requires increasing amounts to produce the same effect, or the same amount produces a diminished response. It is one criterion for substance use disorder.", difficulty: 1, category: "Substance Use Disorders", topic: "Core Concepts" },
  { id: "cac-562", stem: "When developing a relapse prevention plan, which component is MOST essential?", options: ["Identification of personal high-risk situations with specific coping strategies for each","A list of punishments for relapse","Commitment to never experiencing any negative emotions","A guarantee from the client that they will never use again"], correctIndex: 0, rationale: "Effective relapse prevention plans are individualized, identifying specific high-risk situations, early warning signs, and concrete coping strategies. They should also include emergency contacts and crisis plans.", difficulty: 2, category: "Relapse Prevention", topic: "Planning" },
  { id: "cac-563", stem: "A counselor who shares their own recovery story with a client is engaging in:", options: ["Self-disclosure, which should be used judiciously and only when it serves the client's therapeutic goals","Boundary violation that is never appropriate","Standard practice required in all addiction counseling","Counter-transference that must be avoided"], correctIndex: 0, rationale: "Self-disclosure in addiction counseling can be therapeutic when used purposefully, briefly, and in the client's interest. It should normalize the recovery experience without shifting focus from the client.", difficulty: 2, category: "Ethics", topic: "Professional Boundaries" },
  { id: "cac-564", stem: "Fetal alcohol syndrome (FAS) is characterized by:", options: ["Facial dysmorphology, growth deficiency, and central nervous system abnormalities","Only low birth weight with no other features","Symptoms that resolve completely by age 5","Hyperactivity that is indistinguishable from ADHD"], correctIndex: 0, rationale: "FAS involves characteristic facial features (smooth philtrum, thin upper lip, short palpebral fissures), prenatal/postnatal growth deficiency, and CNS abnormalities including intellectual disability.", difficulty: 2, category: "Substance Use Disorders", topic: "Prenatal Effects" },
  { id: "cac-565", stem: "The primary goal of a screening instrument like the AUDIT (Alcohol Use Disorders Identification Test) is to:", options: ["Identify individuals with hazardous or harmful alcohol consumption who may benefit from intervention","Diagnose alcohol use disorder","Determine the appropriate medication for treatment","Assess the client's personality characteristics"], correctIndex: 0, rationale: "The AUDIT is a 10-item WHO screening tool designed to identify hazardous, harmful, and dependent drinking patterns. Screening identifies risk; diagnosis requires comprehensive clinical assessment.", difficulty: 1, category: "Clinical Assessment", topic: "Screening Tools" },
  { id: "cac-566", stem: "A counselor learns that a client is HIV-positive and continues to share needles without informing partners. The counselor's ethical obligation involves:", options: ["Consulting applicable duty-to-warn laws and agency policy while considering the limits of confidentiality","Immediately contacting all known partners without client consent","Maintaining strict confidentiality regardless of risk to others","Discharging the client from treatment"], correctIndex: 0, rationale: "This presents an ethical dilemma between confidentiality and duty to protect. State laws on duty to warn vary, and 42 CFR Part 2 has specific provisions. Consultation with supervisors and legal counsel is essential.", difficulty: 4, category: "Ethics", topic: "Duty to Warn" },
  { id: "cac-567", stem: "Motivational interviewing was originally developed by:", options: ["William Miller","Carl Rogers","Aaron Beck","Sigmund Freud"], correctIndex: 0, rationale: "William Miller first described motivational interviewing in 1983, later developing it further with Stephen Rollnick. It drew on person-centered counseling, cognitive dissonance theory, and self-perception theory.", difficulty: 1, category: "Motivational Interviewing", topic: "History" },
  { id: "cac-568", stem: "A client in recovery attends a wedding where alcohol is served. According to Marlatt's model, which internal factor MOST increases relapse risk?", options: ["Positive outcome expectancies about the effects of alcohol","The physical presence of alcohol alone","The time of day the event occurs","The number of people at the wedding"], correctIndex: 0, rationale: "Positive outcome expectancies (e.g., 'One drink will make me more social and relaxed') combined with a high-risk situation significantly increase relapse probability in Marlatt's cognitive-behavioral model.", difficulty: 3, category: "Relapse Prevention", topic: "Cognitive Factors" },
  { id: "cac-569", stem: "Which level of ASAM care corresponds to medically managed intensive inpatient treatment?", options: ["Level 4.0","Level 1.0","Level 2.1","Level 3.1"], correctIndex: 0, rationale: "ASAM Level 4.0 is medically managed intensive inpatient treatment, typically in a hospital setting with 24-hour medical and nursing care for severe withdrawal or acute medical/psychiatric conditions.", difficulty: 2, category: "Clinical Assessment", topic: "Level of Care" },
  { id: "cac-570", stem: "When working with older adults who have substance use disorders, counselors should be aware that:", options: ["Physiological changes of aging increase sensitivity to substances and risk of adverse effects","Older adults rarely develop new substance use problems","Alcohol use disorders in older adults do not require treatment","Standard dosing recommendations apply regardless of age"], correctIndex: 0, rationale: "Aging reduces liver metabolism, decreases body water, and increases body fat, altering drug pharmacokinetics. Lower doses produce greater effects, and drug interactions with medications are more common.", difficulty: 2, category: "Special Populations", topic: "Older Adults" },
  { id: "cac-571", stem: "A client in outpatient treatment tests positive for fentanyl despite reporting abstinence from opioids. The counselor should FIRST:", options: ["Discuss the result non-judgmentally and reassess the treatment plan, including safety concerns about fentanyl potency","Discharge the client for dishonesty","Report the positive test to law enforcement","Ignore the discrepancy to maintain the therapeutic relationship"], correctIndex: 0, rationale: "Fentanyl's extreme potency makes any use a significant overdose risk. Addressing the result non-judgmentally maintains therapeutic rapport while allowing for critical safety planning and treatment adjustment.", difficulty: 2, category: "Counseling Fundamentals", topic: "Clinical Decision-Making" },
  { id: "cac-572", stem: "The disease model of addiction conceptualizes substance use disorders as:", options: ["A chronic, relapsing brain disease with genetic, neurobiological, and environmental components","A moral failing requiring punishment","A choice that can be stopped through willpower alone","A temporary condition that resolves without treatment"], correctIndex: 0, rationale: "The disease model views addiction as a chronic brain disease involving changes in reward, motivation, and memory circuits. It has genetic vulnerability, environmental triggers, and requires ongoing management.", difficulty: 1, category: "Theories of Addiction", topic: "Disease Model" },
  { id: "cac-573", stem: "In a therapeutic community, the concept of 'community as method' means:", options: ["The entire community environment, including peers and staff, serves as the primary therapeutic agent","Only licensed therapists provide treatment","Community members make all medical decisions","Clients are isolated from each other to prevent negative influence"], correctIndex: 0, rationale: "In TC philosophy, the community itself (structured environment, peer interactions, role modeling, hierarchy of responsibilities) is the primary vehicle for change, not individual therapy alone.", difficulty: 3, category: "Treatment Modalities", topic: "Therapeutic Communities" },
  { id: "cac-574", stem: "A counselor working with a client who uses both heroin and methamphetamine (speedballing) should understand that:", options: ["The combination increases overdose risk because stimulant effects can mask opioid respiratory depression","Using both substances simultaneously cancels out all negative effects","Methamphetamine protects against opioid overdose","This combination is safer than using either substance alone"], correctIndex: 0, rationale: "Speedballing is extremely dangerous because stimulant effects can mask opioid-induced respiratory depression. When stimulant effects wear off first, unopposed opioid respiratory depression can be fatal.", difficulty: 3, category: "Substance Use Disorders", topic: "Polysubstance Use" },
  { id: "cac-575", stem: "The 'decisional balance' exercise in motivational interviewing involves:", options: ["Exploring the pros and cons of both changing and not changing substance use behavior","Telling the client all the reasons they need to change","Providing a list of consequences of continued use","Making the decision for the client based on clinical judgment"], correctIndex: 0, rationale: "Decisional balance is a 2×2 matrix exploring benefits and costs of both changing and maintaining current behavior. It helps clients articulate and weigh their own reasons for and against change.", difficulty: 2, category: "Motivational Interviewing", topic: "Techniques" },
  { id: "cac-576", stem: "A client with methamphetamine use disorder presents with severe dental decay, skin lesions, and significant weight loss. These are recognized as:", options: ["Common physical consequences of chronic methamphetamine use","Unrelated medical conditions requiring separate referral","Signs of a nutritional deficiency only","Indicators of an underlying autoimmune condition"], correctIndex: 0, rationale: "Chronic methamphetamine use causes severe dental problems ('meth mouth'), skin picking leading to lesions, decreased appetite with weight loss, and premature aging due to vasoconstriction and poor self-care.", difficulty: 1, category: "Substance Use Disorders", topic: "Physical Consequences" },
  { id: "cac-577", stem: "Solution-focused brief therapy in addiction treatment emphasizes:", options: ["Identifying and amplifying client strengths and past successes rather than analyzing problems in depth","Extensive exploration of the history and etiology of the addiction","Long-term psychodynamic exploration of unconscious processes","Prescriptive homework assignments based on counselor expertise"], correctIndex: 0, rationale: "SFBT focuses on solutions rather than problems, asking about exceptions (times when the problem doesn't occur), scaling questions, and the miracle question to envision a preferred future.", difficulty: 2, category: "Treatment Modalities", topic: "Brief Therapies" },
  { id: "cac-578", stem: "Naloxone (Narcan) is used in emergency situations to:", options: ["Rapidly reverse opioid overdose by competitively binding to opioid receptors","Treat alcohol poisoning","Reverse benzodiazepine overdose","Prevent stimulant-induced cardiac events"], correctIndex: 0, rationale: "Naloxone is a competitive opioid antagonist that rapidly displaces opioids from receptors, reversing respiratory depression. Its short half-life may require repeated doses, especially with long-acting opioids.", difficulty: 1, category: "Pharmacology", topic: "Emergency Pharmacology" },
  { id: "cac-579", stem: "A counselor who consistently feels angry and punitive toward a particular client who reminds them of an abusive family member is experiencing:", options: ["Countertransference, which requires supervision and self-awareness to manage appropriately","A normal reaction that requires no attention","Burnout that can only be resolved by changing careers","Transference from the client"], correctIndex: 0, rationale: "Countertransference involves the counselor's unconscious emotional reactions to a client based on the counselor's own experiences. Regular supervision and self-awareness are essential for ethical practice.", difficulty: 2, category: "Counseling Fundamentals", topic: "Clinical Supervision" },
  { id: "cac-580", stem: "The SBIRT model stands for:", options: ["Screening, Brief Intervention, and Referral to Treatment","Substance, Behavioral, Intervention, Recovery, Treatment","Systematic Biological Intervention and Recovery Therapy","Screening, Behavioral Insight, Response, and Transition"], correctIndex: 0, rationale: "SBIRT is an evidence-based public health approach: Screening identifies risk, Brief Intervention provides awareness and motivation, and Referral to Treatment connects those needing more intensive services.", difficulty: 1, category: "Clinical Assessment", topic: "Screening Models" },
  { id: "cac-581", stem: "In treating gambling disorder, which therapeutic approach has the strongest evidence base?", options: ["Cognitive-behavioral therapy targeting erroneous gambling cognitions","Psychopharmacology with stimulant medications","Aversion therapy using electric shock","Hypnotherapy exclusively"], correctIndex: 0, rationale: "CBT for gambling disorder addresses cognitive distortions (illusion of control, gambler's fallacy, superstitious thinking) and behavioral patterns. It has the strongest evidence base among psychosocial treatments.", difficulty: 3, category: "Behavioral Addictions", topic: "Gambling Disorder" },
  { id: "cac-582", stem: "A client in recovery asks the counselor on a date. The counselor should:", options: ["Decline clearly, explain the professional boundary, and process the interaction in supervision","Accept if the client has been discharged from treatment for at least 30 days","Agree to meet outside of treatment to discuss it further","Refer the client to another counselor and then pursue the relationship"], correctIndex: 0, rationale: "Romantic or sexual relationships with current clients are never appropriate. Most ethical codes prohibit such relationships for a minimum period (often 2-5 years) after treatment ends.", difficulty: 1, category: "Ethics", topic: "Professional Boundaries" },
  { id: "cac-583", stem: "Neonatal abstinence syndrome (NAS) occurs when:", options: ["A newborn experiences withdrawal symptoms after prenatal exposure to opioids or other substances","A newborn is allergic to formula","A mother abstains from substances during pregnancy causing fetal distress","An infant develops substance dependence through breastfeeding alone"], correctIndex: 0, rationale: "NAS results from prenatal substance exposure, most commonly opioids. Symptoms include irritability, tremors, poor feeding, high-pitched cry, and seizures, typically appearing within 24-72 hours of birth.", difficulty: 2, category: "Substance Use Disorders", topic: "Prenatal Effects" },
  { id: "cac-584", stem: "The primary difference between a 'lapse' and a 'relapse' in addiction recovery is:", options: ["A lapse is a brief, limited return to use, while a relapse is a sustained return to previous patterns of use","There is no difference between the two terms","A lapse is more severe than a relapse","A lapse only applies to alcohol, while relapse applies to all substances"], correctIndex: 0, rationale: "Distinguishing lapse (slip, single episode) from relapse (return to sustained pattern) is therapeutically important. A lapse can be a learning opportunity, while preventing its progression to relapse is key.", difficulty: 1, category: "Relapse Prevention", topic: "Definitions" },
  { id: "cac-585", stem: "When a counselor suspects a client is experiencing domestic violence in addition to substance use, the MOST appropriate action is:", options: ["Screen for domestic violence using a validated tool and develop a safety plan if indicated","Focus exclusively on the substance use disorder and defer DV issues","Confront the suspected abuser directly","Report to law enforcement without the client's knowledge or consent"], correctIndex: 0, rationale: "Domestic violence and substance use commonly co-occur. Safety screening, collaborative safety planning, and connection to DV resources should be integrated into treatment while respecting client autonomy.", difficulty: 2, category: "Crisis Intervention", topic: "Domestic Violence" },
  { id: "cac-586", stem: "The phenomenon of 'kindling' in alcohol withdrawal refers to:", options: ["Progressive worsening of withdrawal symptoms with each successive withdrawal episode","The initial onset of withdrawal symptoms","A gradual decrease in withdrawal severity over time","The process of developing tolerance to alcohol"], correctIndex: 0, rationale: "Kindling describes how repeated alcohol withdrawal episodes become progressively more severe due to neuroadaptation. Each withdrawal sensitizes the brain, increasing seizure risk in subsequent episodes.", difficulty: 4, category: "Substance Use Disorders", topic: "Withdrawal Syndromes" },
  { id: "cac-587", stem: "In group therapy, the stage of development characterized by conflict, resistance, and testing of boundaries is called:", options: ["Storming","Forming","Norming","Performing"], correctIndex: 0, rationale: "Tuckman's model identifies Storming as the conflict stage where members test limits, challenge leadership, and establish hierarchy. Effective facilitation helps groups navigate this stage productively.", difficulty: 2, category: "Group Therapy", topic: "Group Development" },
  { id: "cac-588", stem: "A client with cocaine use disorder reports persistent depression 6 weeks after achieving abstinence. This MOST likely represents:", options: ["Substance-induced mood disorder that may persist during early recovery due to dopamine depletion","A pre-existing major depressive disorder requiring immediate medication","A normal state that requires no clinical attention","Evidence that recovery is not possible for this client"], correctIndex: 0, rationale: "Chronic cocaine use depletes dopamine, causing anhedonia and depression that can persist for weeks to months after cessation. Distinguishing substance-induced from independent mood disorders requires observation over time.", difficulty: 3, category: "Co-Occurring Disorders", topic: "Differential Diagnosis" },
  { id: "cac-589", stem: "A counselor practicing within scope of practice should refer a client to a physician when:", options: ["The client reports new physical symptoms that may require medical evaluation or medication management","The client expresses feelings of sadness","The client requests a higher level of care","The client's insurance changes"], correctIndex: 0, rationale: "Counselors must recognize the boundaries of their competence. Medical symptoms, medication needs, and physical health concerns require physician evaluation. This is both an ethical and safety obligation.", difficulty: 1, category: "Ethics", topic: "Scope of Practice" },
  { id: "cac-590", stem: "The Matrix Model for stimulant addiction treatment integrates:", options: ["CBT, family education, twelve-step facilitation, relapse prevention, and drug testing in a structured outpatient format","Only individual psychotherapy sessions","Exclusively pharmacological interventions","Inpatient detoxification followed by no outpatient care"], correctIndex: 0, rationale: "The Matrix Model is an evidence-based intensive outpatient program combining multiple approaches: CBT, relapse prevention, family/group sessions, twelve-step facilitation, and urine testing over 16 weeks.", difficulty: 3, category: "Treatment Modalities", topic: "Structured Programs" },
  { id: "cac-591", stem: "When treating a client from a collectivist culture, the counselor should consider:", options: ["Involving family members in treatment planning as culturally appropriate and desired by the client","Insisting on individual treatment only, as family involvement is never helpful","Assuming all members of the culture share identical beliefs about addiction","Applying Western individualistic treatment models without modification"], correctIndex: 0, rationale: "Collectivist cultures prioritize family and community interconnection. Treatment that includes family, respects cultural healing practices, and considers collective identity is more culturally responsive.", difficulty: 2, category: "Cultural Competence", topic: "Collectivist Cultures" },
  { id: "cac-592", stem: "Which of the following is a recognized protective factor against developing substance use disorders?", options: ["Strong prosocial bonds and involvement in community activities","Early exposure to substance use in the home","Association with substance-using peers","Unmonitored free time during adolescence"], correctIndex: 0, rationale: "Prosocial bonds, community involvement, positive family relationships, and school engagement are well-established protective factors that reduce risk of developing substance use disorders.", difficulty: 1, category: "Theories of Addiction", topic: "Risk and Protective Factors" },
  { id: "cac-593", stem: "A client on methadone maintenance is admitted to the hospital for emergency surgery. The surgical team should be advised that:", options: ["Methadone does not provide adequate analgesia for acute surgical pain, and additional pain management will be needed","Methadone will provide sufficient pain relief and no additional medication is needed","All opioid medications should be discontinued immediately","The client's methadone dose should be halved during hospitalization"], correctIndex: 0, rationale: "Patients on methadone maintenance have opioid tolerance, so their maintenance dose manages cravings/withdrawal but does not provide acute pain relief. Additional short-acting opioids or non-opioid analgesics are typically needed.", difficulty: 4, category: "Pharmacology", topic: "Pain Management" },
  { id: "cac-594", stem: "The concept of 'recovery capital' refers to:", options: ["The internal and external resources a person can draw upon to initiate and sustain recovery","The financial cost of addiction treatment","Insurance coverage for substance use treatment","Government funding for treatment programs"], correctIndex: 0, rationale: "Recovery capital encompasses social capital (relationships, support), physical capital (health, housing, finances), human capital (education, skills), and cultural capital (values, beliefs) that support recovery.", difficulty: 2, category: "Theories of Addiction", topic: "Recovery Concepts" },
  { id: "cac-595", stem: "A counselor is facilitating a psychoeducation group about the effects of alcohol on the liver. Which condition represents the MOST severe form of alcohol-related liver disease?", options: ["Cirrhosis with portal hypertension","Fatty liver (steatosis)","Mild hepatitis","Elevated liver enzymes without structural damage"], correctIndex: 0, rationale: "Alcohol-related liver disease progresses from fatty liver to alcoholic hepatitis to cirrhosis. Cirrhosis with portal hypertension represents irreversible scarring with complications including varices and ascites.", difficulty: 2, category: "Substance Use Disorders", topic: "Medical Complications" },
  { id: "cac-596", stem: "A counselor using the transtheoretical model notes a client is taking specific steps like attending meetings and seeing a therapist weekly. The client is in the:", options: ["Action stage","Preparation stage","Contemplation stage","Precontemplation stage"], correctIndex: 0, rationale: "The Action stage involves overt behavioral changes in the past 6 months. Attending meetings and therapy represent active, observable modifications to substance use behavior.", difficulty: 1, category: "Theories of Addiction", topic: "Stages of Change" },
  { id: "cac-597", stem: "When conducting an assessment, open-ended questions are preferred over closed-ended questions because they:", options: ["Encourage detailed responses and exploration of the client's perspective and experience","Allow the counselor to control the conversation more effectively","Take less time to administer","Produce quantifiable data for insurance reporting"], correctIndex: 0, rationale: "Open-ended questions (who, what, how, tell me about) elicit richer information, support client autonomy, and are more consistent with motivational approaches than yes/no questions.", difficulty: 1, category: "Clinical Assessment", topic: "Interview Techniques" },
  { id: "cac-598", stem: "The primary psychoactive compound in cannabis that produces the 'high' is:", options: ["Delta-9-tetrahydrocannabinol (THC)","Cannabidiol (CBD)","Cannabinol (CBN)","Terpinolene"], correctIndex: 0, rationale: "THC is the primary psychoactive cannabinoid responsible for the euphoric and intoxicating effects of cannabis. CBD is non-intoxicating and has potential therapeutic properties.", difficulty: 1, category: "Substance Use Disorders", topic: "Cannabis" },
  { id: "cac-599", stem: "In treating individuals with post-traumatic stress disorder and co-occurring substance use disorder, the recommended approach is:", options: ["Integrated treatment addressing both conditions simultaneously using trauma-informed approaches","Treating PTSD first, then addressing substance use after trauma symptoms resolve","Treating substance use first, as trauma work is contraindicated during active use","Separating treatment into two distinct programs with different providers"], correctIndex: 0, rationale: "Integrated models like Seeking Safety address both conditions simultaneously. Research shows that treating PTSD does not worsen substance use, and integrated treatment produces better outcomes than sequential treatment.", difficulty: 3, category: "Co-Occurring Disorders", topic: "PTSD and SUD" },
  { id: "cac-600", stem: "The counselor's use of 'change talk' in motivational interviewing refers to:", options: ["Client statements that favor movement toward positive change, which the counselor selectively reinforces","The counselor lecturing the client about the need to change","Persuasive arguments designed to overcome client resistance","Technical clinical language used in documentation"], correctIndex: 0, rationale: "Change talk includes client statements expressing desire, ability, reasons, need, commitment, activation, and taking steps toward change (DARN-CAT). The counselor elicits and reinforces these statements.", difficulty: 2, category: "Motivational Interviewing", topic: "Change Talk" }
];
